  1→//! Git operations for the autoresearch experiment loop.
  2→//!
  3→//! Provides [`AutoresearchGitOps`] which wraps a project directory and tracks
  4→//! the last "kept" commit SHA, enabling keep/discard mutation cycles via real
  5→//! git operations (branch creation, commits, hard resets).
  6→
  7→use std::path::{Path, PathBuf};
  8→use std::sync::Mutex;
  9→
 10→use anyhow::{Context, Result};
 11→use git2::{IndexAddOption, Repository, ResetType, Signature};
 12→
 13→use super::loop_runner::LoopGitOps;
 14→
 15→/// Core struct for autoresearch git operations.
 16→///
 17→/// Opens `git2::Repository` on demand (via [`open_repo`](Self::open_repo)) to
 18→/// avoid borrow-lifetime issues. Tracks the last committed ("kept") SHA so the
 19→/// loop can discard mutations by resetting to it.
 20→pub struct AutoresearchGitOps {
 21→    project_dir: PathBuf,
 22→    last_keep_sha: Mutex<Option<String>>,
 23→}
 24→
 25→impl AutoresearchGitOps {
 26→    /// Create a new `AutoresearchGitOps` for the given project directory.
 27→    pub fn new(project_dir: &Path) -> Self {
 28→        Self {
 29→            project_dir: project_dir.to_path_buf(),
 30→            last_keep_sha: Mutex::new(None),
 31→        }
 32→    }
 33→
 34→    /// Open the git repository at `project_dir`.
 35→    fn open_repo(&self) -> Result<Repository> {
 36→        Repository::open(&self.project_dir)
 37→            .with_context(|| format!("failed to open git repository at {:?}", self.project_dir))
 38→    }
 39→}
 40→
 41→impl LoopGitOps for AutoresearchGitOps {
 42→    fn create_branch(&self, branch_name: &str) -> Result<()> {
 43→        let repo = self.open_repo()?;
 44→        let head_commit = repo
 45→            .head()
 46→            .context("failed to get HEAD reference")?
 47→            .peel_to_commit()
 48→            .context("failed to peel HEAD to commit")?;
 49→
 50→        let sha = head_commit.id().to_string();
 51→
 52→        repo.branch(branch_name, &head_commit, false)
 53→            .with_context(|| format!("failed to create branch '{branch_name}'"))?;
 54→        repo.set_head(&format!("refs/heads/{branch_name}"))
 55→            .with_context(|| format!("failed to set HEAD to branch '{branch_name}'"))?;
 56→        repo.checkout_head(Some(git2::build::CheckoutBuilder::new().force()))
 57→            .context("failed to checkout HEAD after branch creation")?;
 58→
 59→        let mut guard = self.last_keep_sha.lock().expect("lock poisoned");
 60→        *guard = Some(sha);
 61→
 62→        Ok(())
 63→    }
 64→
 65→    fn checkout_branch(&self, branch_name: &str) -> Result<()> {
 66→        let repo = self.open_repo()?;
 67→
 68→        repo.set_head(&format!("refs/heads/{branch_name}"))
 69→            .with_context(|| format!("failed to set HEAD to branch '{branch_name}'"))?;
 70→        repo.checkout_head(Some(git2::build::CheckoutBuilder::new().force()))
 71→            .with_context(|| format!("failed to checkout branch '{branch_name}'"))?;
 72→
 73→        let head_commit = repo
 74→            .head()
 75→            .context("failed to get HEAD after checkout")?
 76→            .peel_to_commit()
 77→            .context("failed to peel HEAD to commit after checkout")?;
 78→
 79→        let sha = head_commit.id().to_string();
 80→        let mut guard = self.last_keep_sha.lock().expect("lock poisoned");
 81→        *guard = Some(sha);
 82→
 83→        Ok(())
 84→    }
 85→
 86→    fn commit(&self, message: &str) -> Result<String> {
 87→        let repo = self.open_repo()?;
 88→
 89→        let mut index = repo.index().context("failed to get repository index")?;
 90→        index
 91→            .add_all(["*"].iter(), IndexAddOption::DEFAULT, None)
 92→            .context("failed to stage changes")?;
 93→        index.write().context("failed to write index")?;
 94→
 95→        let tree_id = index.write_tree().context("failed to write tree")?;
 96→        let tree = repo
 97→            .find_tree(tree_id)
 98→            .context("failed to find tree from index")?;
 99→
100→        let sig = Signature::now("forge-autoresearch", "forge@localhost")
101→            .context("failed to create commit signature")?;
102→
103→        let head_commit = repo
104→            .head()
105→            .context("failed to get HEAD for commit")?
106→            .peel_to_commit()
107→            .context("failed to peel HEAD to commit for parent")?;
108→
109→        let oid = repo
110→            .commit(Some("HEAD"), &sig, &sig, message, &tree, &[&head_commit])
111→            .context("failed to create commit")?;
112→
113→        let sha = oid.to_string();
114→        let mut guard = self.last_keep_sha.lock().expect("lock poisoned");
115→        *guard = Some(sha.clone());
116→
117→        Ok(sha)
118→    }
119→
120→    fn reset_to_last_keep(&self) -> Result<()> {
121→        let sha = {
122→            let guard = self.last_keep_sha.lock().expect("lock poisoned");
123→            guard.clone()
124→        };
125→
126→        let sha = sha.ok_or_else(|| {
127→            anyhow::anyhow!("no last_keep_sha set — call create_branch or commit first")
128→        })?;
129→
130→        let repo = self.open_repo()?;
131→        let oid = git2::Oid::from_str(&sha)
132→            .with_context(|| format!("invalid SHA '{sha}'"))?;
133→        let commit = repo
134→            .find_commit(oid)
135→            .with_context(|| format!("failed to find commit '{sha}'"))?;
136→        let obj = commit.as_object();
137→        repo.reset(obj, ResetType::Hard, None)
138→            .with_context(|| format!("failed to hard-reset to commit '{sha}'"))?;
139→
140→        Ok(())
141→    }
142→
143→    fn head_sha(&self) -> Result<String> {
144→        let repo = self.open_repo()?;
145→        let head = repo
146→            .head()
147→            .context("failed to get HEAD reference")?
148→            .peel_to_commit()
149→            .context("failed to peel HEAD to commit")?;
150→        Ok(head.id().to_string())
151→    }
152→}
