160→    /// Create a temp directory with an initialized git repo and an initial commit,
161→    /// returning the `AutoresearchGitOps` and the `TempDir` (kept alive for the test).
162→    fn setup_repo() -> (AutoresearchGitOps, tempfile::TempDir) {
163→        let dir = tempdir().expect("failed to create tempdir");
164→        let repo = Repository::init(dir.path()).expect("failed to init repo");
165→
166→        // Configure identity for commits.
167→        let mut config = repo.config().expect("failed to get repo config");
168→        config
169→            .set_str("user.name", "Test User")
170→            .expect("set user.name");
171→        config
172→            .set_str("user.email", "test@example.com")
173→            .expect("set user.email");
174→
175→        // Create an initial commit so HEAD exists.
176→        fs::write(dir.path().join("init.txt"), "init\n").expect("write init.txt");
177→        let mut index = repo.index().expect("get index");
178→        index
179→            .add_all(["*"].iter(), IndexAddOption::DEFAULT, None)
180→            .expect("stage");
181→        index.write().expect("write index");
182→        let tree_id = index.write_tree().expect("write tree");
183→        let tree = repo.find_tree(tree_id).expect("find tree");
184→        let sig = Signature::now("Test", "test@test.com").expect("sig");
185→        repo.commit(Some("HEAD"), &sig, &sig, "initial commit", &tree, &[])
186→            .expect("initial commit");
187→
188→        let ops = AutoresearchGitOps::new(dir.path());
189→        (ops, dir)
190→    }
