326→    #[test]
327→    fn test_reset_to_last_keep_reverts_changes() {
328→        let (ops, dir) = setup_repo();
329→        ops.create_branch("reset-test").expect("create_branch");
330→
331→        // Commit a baseline file.
332→        let baseline_path = dir.path().join("baseline.txt");
333→        fs::write(&baseline_path, "original\n").expect("write baseline");
334→        ops.commit("baseline").expect("commit baseline");
335→
336→        // Make uncommitted changes — a new file and a modification.
337→        let extra_path = dir.path().join("extra.txt");
338→        fs::write(&extra_path, "extra\n").expect("write extra");
339→        fs::write(&baseline_path, "modified\n").expect("modify baseline");
340→
341→        // Verify changes exist before reset.
342→        assert_eq!(
343→            fs::read_to_string(&baseline_path).expect("read"),
344→            "modified\n"
345→        );
346→        assert!(extra_path.exists(), "extra.txt must exist before reset");
347→
348→        // Reset.
349→        ops.reset_to_last_keep().expect("reset_to_last_keep");
350→
351→        // Baseline must be reverted.
352→        assert_eq!(
353→            fs::read_to_string(&baseline_path).expect("read after reset"),
354→            "original\n",
355→            "baseline.txt must be reverted to the committed content"
356→        );
357→    }
