372→    /// Return the default branch name for the repo (e.g., "main" or "master").
373→    fn default_branch_name(ops: &AutoresearchGitOps) -> String {
374→        let repo = ops.open_repo().expect("open repo");
375→        // Before create_branch, HEAD points to the default branch.
