380→    #[test]
381→    fn test_checkout_branch_switches_to_existing_branch() {
382→        let (ops, _dir) = setup_repo();
383→        let default = default_branch_name(&ops);
384→
385→        // Create a branch, then switch back to default, then checkout the branch.
386→        ops.create_branch("side-branch").expect("create");
387→        let repo = ops.open_repo().expect("open");
388→        repo.set_head(&format!("refs/heads/{default}"))
389→            .expect("switch back to default branch");
390→        repo.checkout_head(Some(git2::build::CheckoutBuilder::new().force()))
391→            .expect("checkout default");
392→
393→        ops.checkout_branch("side-branch")
394→            .expect("checkout_branch should succeed");
