402→    #[test]
403→    fn test_checkout_branch_sets_last_keep_sha() {
404→        let (ops, _dir) = setup_repo();
405→        let default = default_branch_name(&ops);
406→
407→        ops.create_branch("sha-branch").expect("create");
408→        let branch_sha = ops.head_sha().expect("head_sha on branch");
409→
410→        // Switch away.
411→        let repo = ops.open_repo().expect("open");
412→        repo.set_head(&format!("refs/heads/{default}"))
413→            .expect("switch back");
414→        repo.checkout_head(Some(git2::build::CheckoutBuilder::new().force()))
415→            .expect("checkout");
416→
417→        // Clear last_keep_sha manually to prove checkout_branch sets it.
418→        {
419→            let mut guard = ops.last_keep_sha.lock().expect("lock");
420→            *guard = None;
421→        }
422→
423→        ops.checkout_branch("sha-branch").expect("checkout_branch");
424→        let guard = ops.last_keep_sha.lock().expect("lock");
425→        assert_eq!(
426→            guard.as_deref(),
427→            Some(branch_sha.as_str()),
428→            "last_keep_sha must be set to the branch tip SHA"
429→        );
430→    }
