504→    #[test]
505→    fn test_trait_checkout_existing_branch() {
506→        let (ops, _dir) = setup_trait_ops();
507→
508→        // Remember HEAD before branching.
509→        let _original_sha = ops.head_sha().expect("original sha");
510→
511→        ops.create_branch("trait-side").expect("create side branch");
512→        // create_branch already checks it out, so switch back manually using
513→        // a second create_branch call on a different name — but instead let's
514→        // just verify checkout_branch works by creating, committing on side,
515→        // then checking out the side branch from a state where we know the SHA.
516→        let side_sha = ops.head_sha().expect("side sha");
517→
518→        // Checkout the branch again (idempotent) — should succeed and set keep SHA.
519→        ops.checkout_branch("trait-side").expect("checkout via trait");
520→        assert_eq!(ops.head_sha().expect("after checkout"), side_sha);
521→    }
