523→    #[test]
524→    fn test_trait_full_keep_discard_cycle() {
525→        let (ops, dir) = setup_trait_ops();
526→        ops.create_branch("trait-cycle").expect("create_branch");
527→
528→        // KEEP: commit a file.
529→        let kept = dir.path().join("kept.txt");
530→        fs::write(&kept, "kept\n").expect("write kept");
531→        let keep_sha = ops.commit("keep").expect("commit keep");
532→
533→        // DISCARD: write a file but don't commit.
534→        let discarded = dir.path().join("discarded.txt");
535→        fs::write(&discarded, "gone\n").expect("write discarded");
536→        assert!(discarded.exists());
537→
538→        ops.reset_to_last_keep().expect("reset");
539→
540→        assert!(kept.exists(), "kept file must survive reset");
541→        assert_eq!(ops.head_sha().expect("head"), keep_sha);
542→    }
