544→    #[test]
545→    fn test_trait_multiple_keep_discard_cycles() {
546→        let (ops, dir) = setup_trait_ops();
547→        ops.create_branch("trait-multi").expect("create_branch");
548→
549→        // Cycle 1: keep — commit a tracked file.
550→        let tracked = dir.path().join("tracked.txt");
551→        fs::write(&tracked, "v1\n").expect("write");
552→        let sha1 = ops.commit("iteration 1").expect("commit 1");
553→
554→        // Cycle 2: discard — modify the tracked file, then reset.
555→        fs::write(&tracked, "bad mutation\n").expect("modify");
556→        ops.reset_to_last_keep().expect("discard 2");
557→        assert_eq!(ops.head_sha().expect("head"), sha1);
558→        assert_eq!(fs::read_to_string(&tracked).expect("read"), "v1\n");
559→
560→        // Cycle 3: keep — update the tracked file and commit.
561→        fs::write(&tracked, "v3\n").expect("write v3");
562→        let sha3 = ops.commit("iteration 3").expect("commit 3");
563→        assert_ne!(sha1, sha3);
564→
565→        // Cycle 4: discard — modify again, then reset.
566→        fs::write(&tracked, "bad mutation 2\n").expect("modify");
567→        ops.reset_to_last_keep().expect("discard 4");
568→        assert_eq!(ops.head_sha().expect("head"), sha3);
569→        assert_eq!(fs::read_to_string(&tracked).expect("read"), "v3\n");
570→    }
571→
572→    #[test]
573→    fn test_trait_commit_after_reset_works() {
574→        let (ops, dir) = setup_trait_ops();
575→        ops.create_branch("trait-recommit").expect("create_branch");
576→
577→        // Commit, then discard some changes, then commit again.
578→        fs::write(dir.path().join("first.txt"), "first\n").expect("write");
579→        ops.commit("first keep").expect("commit 1");
580→
581→        fs::write(dir.path().join("bad.txt"), "discard me\n").expect("write");
582→        ops.reset_to_last_keep().expect("reset");
583→
584→        // New commit after reset should work.
585→        fs::write(dir.path().join("second.txt"), "second\n").expect("write");
586→        let sha = ops.commit("second keep").expect("commit 2");
587→        assert_eq!(ops.head_sha().expect("head"), sha);
588→        assert!(dir.path().join("first.txt").exists());
589→        assert!(dir.path().join("second.txt").exists());
590→    }
591→
592→    #[test]
593→    fn test_trait_create_branch_duplicate_fails() {
594→        let (ops, _dir) = setup_trait_ops();
595→        ops.create_branch("dup").expect("first create");
596→        let result = ops.create_branch("dup");
597→        assert!(result.is_err(), "duplicate branch creation must fail via trait");
598→    }
599→
600→    #[test]
601→    fn test_trait_checkout_nonexistent_branch_fails() {
602→        let (ops, _dir) = setup_trait_ops();
603→        let result = ops.checkout_branch("does-not-exist");
604→        assert!(result.is_err(), "checkout of nonexistent branch must fail");
605→    }
606→
607→    // --- Full keep/discard cycle (concrete type) ---
608→
609→    #[test]
610→    fn test_full_keep_discard_cycle() {
611→        let (ops, dir) = setup_repo();
612→        ops.create_branch("cycle-test").expect("create_branch");
613→
614→        // --- Iteration 1: KEEP ---
615→        // Create a file and commit (keep the mutation).
616→        let kept_path = dir.path().join("kept.txt");
617→        fs::write(&kept_path, "I am kept\n").expect("write kept");
618→        let keep_sha = ops.commit("keep iteration 1").expect("commit");
619→
620→        // File must exist after keep.
621→        assert!(kept_path.exists(), "kept.txt must exist after keep");
622→
623→        // --- Iteration 2: DISCARD ---
