  1→//! Single experiment step for the autoresearch loop.
  2→//!
  3→//! Proposes a prompt mutation via an LLM, writes it, runs benchmarks,
  4→//! judges outputs, computes cost, and returns a structured `ExperimentResult`
  5→//! with keep/discard outcome.
  6→
  7→use std::path::PathBuf;
  8→
  9→use anyhow::{Context, Result};
 10→use serde::{Deserialize, Serialize};
 11→
 12→// ---------------------------------------------------------------------------
 13→// Core Types
 14→// ---------------------------------------------------------------------------
 15→
 16→/// Benchmark evaluation scores.
 17→#[derive(Debug, Clone, Serialize, Deserialize)]
 18→pub struct BenchmarkScores {
 19→    pub recall: f64,
 20→    pub precision: f64,
 21→    pub actionability: f64,
 22→}
 23→
 24→/// Verdict from running benchmarks and judging outputs.
 25→#[derive(Debug, Clone, Serialize, Deserialize)]
 26→pub struct JudgeVerdict {
 27→    pub scores: BenchmarkScores,
 28→    pub composite_score: f64,
 29→}
 30→
 31→/// Outcome of a single experiment.
 32→#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
 33→#[serde(rename_all = "snake_case")]
 34→pub enum ExperimentOutcome {
 35→    Keep,
 36→    Discard,
 37→    Error,
 38→}
 39→
 40→/// A proposed prompt mutation from the LLM.
 41→#[derive(Debug, Clone, Serialize, Deserialize)]
 42→pub struct MutationProposal {
 43→    pub new_prompt: String,
 44→    pub description: String,
 45→    pub input_tokens: u64,
 46→    pub output_tokens: u64,
 47→}
 48→
 49→/// Configuration for a single experiment run.
 50→#[derive(Debug, Clone, Serialize, Deserialize)]
 51→pub struct ExperimentConfig {
 52→    pub prompt_path: PathBuf,
 53→    pub specialist: String,
 54→    pub baseline_score: f64,
 55→    pub dry_run: bool,
 56→}
 57→
 58→/// Full result of a single experiment.
 59→#[derive(Debug, Clone, Serialize, Deserialize)]
 60→pub struct ExperimentResult {
 61→    pub outcome: ExperimentOutcome,
 62→    pub proposal: MutationProposal,
 63→    pub verdict: Option<JudgeVerdict>,
 64→    pub commit_sha: String,
 65→    pub cost_usd: f64,
 66→    pub specialist: String,
 67→}
 68→
 69→// ---------------------------------------------------------------------------
 70→// Traits
 71→// ---------------------------------------------------------------------------
 72→
 73→/// Proposes prompt mutations for a specialist.
 74→#[async_trait::async_trait]
 75→pub trait PromptMutator: Send + Sync {
 76→    /// Propose a mutation given the current prompt, experiment history, and specialist name.
 77→    async fn propose_mutation(
 78→        &self,
 79→        current_prompt: &str,
 80→        history: &str,
 81→        specialist: &str,
 82→    ) -> Result<MutationProposal>;
 83→}
 84→
 85→/// Runs benchmarks and judges the outputs.
 86→#[async_trait::async_trait]
 87→pub trait BenchmarkExecutor: Send + Sync {
 88→    /// Execute benchmarks and return a judge verdict.
 89→    async fn run_and_judge(&self) -> Result<JudgeVerdict>;
 90→
 91→    /// Token counts (input, output) from the last run, for cost tracking.
 92→    fn last_run_tokens(&self) -> (u64, u64);
 93→}
 94→
 95→// ---------------------------------------------------------------------------
 96→// Core Function
 97→// ---------------------------------------------------------------------------
 98→
 99→/// Run a single experiment: propose mutation, write prompt, run benchmarks,
100→/// determine outcome, and estimate cost.
101→///
102→/// # Steps
103→/// 1. Read current prompt from `config.prompt_path`
104→/// 2. Propose a mutation via `mutator`
105→/// 3. Write mutated prompt to disk (skipped in dry run)
106→/// 4. Generate placeholder commit SHA
107→/// 5. Run benchmarks and judge (skipped in dry run)
108→/// 6. Determine keep/discard outcome
109→/// 7. Estimate cost using Sonnet pricing
110→pub async fn run_single_experiment(
111→    config: &ExperimentConfig,
112→    mutator: &dyn PromptMutator,
113→    executor: &dyn BenchmarkExecutor,
114→    history: &str,
115→) -> Result<ExperimentResult> {
116→    // Step 1: Read current prompt
117→    let current_prompt = std::fs::read_to_string(&config.prompt_path)
118→        .with_context(|| format!("Failed to read prompt: {}", config.prompt_path.display()))?;
119→
120→    // Step 2: Propose mutation
121→    let proposal = mutator
122→        .propose_mutation(&current_prompt, history, &config.specialist)
123→        .await
124→        .context("Mutation proposal failed")?;
125→
126→    // Step 3: Write mutated prompt (skip in dry run)
127→    if !config.dry_run {
128→        std::fs::write(&config.prompt_path, &proposal.new_prompt)
129→            .with_context(|| {
130→                format!(
131→                    "Failed to write mutated prompt: {}",
132→                    config.prompt_path.display()
133→                )
134→            })?;
135→    }
136→
137→    // Step 4: Placeholder commit SHA
138→    let commit_sha = "placeholder".to_string();
139→
140→    // Step 5: Run benchmarks + judge (skip in dry run)
141→    let verdict = if !config.dry_run {
142→        Some(
143→            executor
144→                .run_and_judge()
145→                .await
146→                .context("Benchmark execution failed")?,
147→        )
148→    } else {
149→        None
150→    };
151→
152→    // Step 6: Determine outcome
153→    let outcome = if config.dry_run {
154→        ExperimentOutcome::Keep
155→    } else if verdict.as_ref().unwrap().composite_score > config.baseline_score {
156→        ExperimentOutcome::Keep
157→    } else {
158→        ExperimentOutcome::Discard
159→    };
160→
161→    // Step 7: Estimate cost (Sonnet pricing: $3/MTok input, $15/MTok output)
162→    let (exec_input, exec_output) = if !config.dry_run {
163→        executor.last_run_tokens()
164→    } else {
165→        (0, 0)
166→    };
167→    let total_input = proposal.input_tokens + exec_input;
168→    let total_output = proposal.output_tokens + exec_output;
169→    let cost_usd =
170→        (total_input as f64 / 1_000_000.0) * 3.0 + (total_output as f64 / 1_000_000.0) * 15.0;
171→
172→    Ok(ExperimentResult {
173→        outcome,
174→        proposal,
175→        verdict,
176→        commit_sha,
177→        cost_usd,
178→        specialist: config.specialist.clone(),
179→    })
180→}
181→
182→// ---------------------------------------------------------------------------
183→// Tests
184→// ---------------------------------------------------------------------------
