  1→//! Budget tracking for autoresearch experiment loops.
  2→//!
  3→//! Enforces a total spend cap by estimating cost from token counts and
  4→//! model-specific pricing, persisting spend data for resume, and providing
  5→//! a [`BudgetTracker::can_afford`] gate before each experiment.
  6→
  7→use anyhow::{Context, Result};
  8→use serde::{Deserialize, Serialize};
  9→
 10→/// Pricing tiers for supported LLM models.
 11→///
 12→/// Prices are in USD per million tokens.
 13→#[derive(Debug, Clone, Serialize, Deserialize)]
 14→pub struct ModelPricing {
 15→    pub model_name: String,
 16→    pub input_price_per_mtok: f64,
 17→    pub output_price_per_mtok: f64,
 18→}
 19→
 20→impl ModelPricing {
 21→    /// Claude Sonnet approximate pricing.
 22→    pub fn claude_sonnet() -> Self {
 23→        Self {
 24→            model_name: "claude-sonnet".to_string(),
 25→            input_price_per_mtok: 3.0,
 26→            output_price_per_mtok: 15.0,
 27→        }
 28→    }
 29→
 30→    /// GPT 5.4 approximate pricing.
 31→    pub fn gpt_5_4() -> Self {
 32→        Self {
 33→            model_name: "gpt-5.4".to_string(),
 34→            input_price_per_mtok: 2.0,
 35→            output_price_per_mtok: 8.0,
 36→        }
 37→    }
 38→
 39→    /// Estimate cost for a single call given token counts.
 40→    pub fn estimate_cost(&self, input_tokens: u32, output_tokens: u32) -> f64 {
 41→        let input_cost = (input_tokens as f64 / 1_000_000.0) * self.input_price_per_mtok;
 42→        let output_cost = (output_tokens as f64 / 1_000_000.0) * self.output_price_per_mtok;
 43→        input_cost + output_cost
 44→    }
 45→}
 46→
 47→/// A single cost record for one LLM call.
 48→#[derive(Debug, Clone, Serialize, Deserialize)]
 49→pub struct CostRecord {
 50→    pub model: String,
 51→    pub input_tokens: u32,
 52→    pub output_tokens: u32,
 53→    pub estimated_cost_usd: f64,
 54→    pub description: String,
 55→}
 56→
 57→/// Tracks cumulative spend and enforces a budget cap.
 58→#[derive(Debug, Clone, Serialize, Deserialize)]
 59→pub struct BudgetTracker {
 60→    /// Maximum allowed spend in USD.
 61→    pub budget_cap_usd: f64,
 62→    /// Running total of estimated spend in USD.
 63→    pub total_spent_usd: f64,
 64→    /// Individual cost records (for audit trail).
 65→    pub records: Vec<CostRecord>,
 66→}
 67→
 68→impl BudgetTracker {
 69→    /// Create a new tracker with the given budget cap.
 70→    pub fn new(budget_cap_usd: f64) -> Self {
 71→        Self {
 72→            budget_cap_usd,
 73→            total_spent_usd: 0.0,
 74→            records: Vec::new(),
 75→        }
 76→    }
 77→
 78→    /// Check if there is enough budget remaining for an estimated cost.
 79→    pub fn can_afford(&self, estimated_cost: f64) -> bool {
 80→        self.total_spent_usd + estimated_cost <= self.budget_cap_usd
 81→    }
 82→
 83→    /// Remaining budget in USD, floored at zero.
 84→    pub fn remaining(&self) -> f64 {
 85→        (self.budget_cap_usd - self.total_spent_usd).max(0.0)
 86→    }
 87→
 88→    /// Record a cost. Returns error if this would exceed the budget cap.
 89→    pub fn record_cost(
 90→        &mut self,
 91→        model: &str,
 92→        input_tokens: u32,
 93→        output_tokens: u32,
 94→        pricing: &ModelPricing,
 95→        description: &str,
 96→    ) -> Result<f64> {
 97→        let cost = pricing.estimate_cost(input_tokens, output_tokens);
 98→        if self.total_spent_usd + cost > self.budget_cap_usd {
 99→            anyhow::bail!(
100→                "Budget exceeded: ${:.4} would bring total to ${:.4}, cap is ${:.2}",
101→                cost,
102→                self.total_spent_usd + cost,
103→                self.budget_cap_usd
104→            );
105→        }
106→        self.total_spent_usd += cost;
107→        self.records.push(CostRecord {
108→            model: model.to_string(),
109→            input_tokens,
110→            output_tokens,
111→            estimated_cost_usd: cost,
112→            description: description.to_string(),
113→        });
114→        Ok(cost)
115→    }
116→
117→    /// Restore budget state from a previous experiment count.
118→    ///
119→    /// Each row in results.tsv represents one experiment that cost approximately
120→    /// `avg_cost_per_experiment`. This allows resuming a run without exact cost records.
121→    pub fn restore_from_experiment_count(
122→        &mut self,
123→        experiment_count: usize,
124→        avg_cost_per_experiment: f64,
125→    ) {
126→        let restored_spend = experiment_count as f64 * avg_cost_per_experiment;
127→        self.total_spent_usd = restored_spend;
128→    }
129→
130→    /// Serialize to JSON for persistence.
131→    pub fn to_json(&self) -> Result<String> {
132→        serde_json::to_string_pretty(self).context("Failed to serialize BudgetTracker")
133→    }
134→
135→    /// Deserialize from JSON.
136→    pub fn from_json(json: &str) -> Result<Self> {
137→        serde_json::from_str(json).context("Failed to deserialize BudgetTracker")
138→    }
139→
140→    /// Save to a file path.
141→    pub fn save(&self, path: &std::path::Path) -> Result<()> {
142→        let json = self.to_json()?;
143→        std::fs::write(path, json).context("Failed to write budget tracker file")?;
144→        Ok(())
145→    }
146→
147→    /// Load from a file path. Returns `None` if file does not exist.
148→    pub fn load(path: &std::path::Path) -> Result<Option<Self>> {
149→        if !path.exists() {
150→            return Ok(None);
151→        }
152→        let content =
153→            std::fs::read_to_string(path).context("Failed to read budget tracker file")?;
154→        let tracker = Self::from_json(&content)?;
155→        Ok(Some(tracker))
156→    }
157→}
158→
159→#[cfg(test)]
160→mod tests {
161→    use super::*;
162→
163→    // --- BudgetTracker::new defaults ---
164→
165→    #[test]
166→    fn test_budget_tracker_new_defaults() {
167→        let tracker = BudgetTracker::new(25.0);
168→        assert!((tracker.budget_cap_usd - 25.0).abs() < f64::EPSILON);
169→        assert!((tracker.total_spent_usd - 0.0).abs() < f64::EPSILON);
170→        assert!(tracker.records.is_empty());
171→        assert!((tracker.remaining() - 25.0).abs() < f64::EPSILON);
172→    }
173→
174→    // --- ModelPricing::estimate_cost ---
175→
176→    #[test]
177→    fn test_model_pricing_estimate_cost_claude() {
178→        let pricing = ModelPricing::claude_sonnet();
179→        // 10,000 input tokens at $3/MTok = $0.03
180→        // 2,000 output tokens at $15/MTok = $0.03
181→        // Total = $0.06
182→        let cost = pricing.estimate_cost(10_000, 2_000);
183→        assert!(
184→            (cost - 0.06).abs() < 0.0001,
185→            "expected ~$0.06, got ${:.6}",
186→            cost
187→        );
188→    }
189→
190→    #[test]
191→    fn test_model_pricing_estimate_cost_gpt() {
192→        let pricing = ModelPricing::gpt_5_4();
193→        // 10,000 input tokens at $2/MTok = $0.02
194→        // 2,000 output tokens at $8/MTok = $0.016
195→        // Total = $0.036
196→        let cost = pricing.estimate_cost(10_000, 2_000);
197→        assert!(
198→            (cost - 0.036).abs() < 0.0001,
199→            "expected ~$0.036, got ${:.6}",
200→            cost
201→        );
202→    }
203→
204→    #[test]
205→    fn test_model_pricing_zero_tokens() {
206→        let pricing = ModelPricing::claude_sonnet();
207→        let cost = pricing.estimate_cost(0, 0);
208→        assert!((cost - 0.0).abs() < f64::EPSILON);
209→    }
210→
211→    // --- BudgetTracker::can_afford ---
212→
213→    #[test]
214→    fn test_can_afford_within_budget() {
215→        let tracker = BudgetTracker::new(1.0);
216→        assert!(tracker.can_afford(0.50));
217→        assert!(tracker.can_afford(1.00)); // exactly at cap
218→    }
219→
220→    #[test]
221→    fn test_can_afford_exceeds_budget() {
222→        let tracker = BudgetTracker::new(1.0);
223→        assert!(!tracker.can_afford(1.01));
224→    }
225→
226→    #[test]
227→    fn test_can_afford_after_spending() {
228→        let mut tracker = BudgetTracker::new(1.0);
229→        let pricing = ModelPricing::claude_sonnet();
230→        // Spend ~$0.06
231→        tracker
232→            .record_cost("claude", 10_000, 2_000, &pricing, "test call")
233→            .unwrap();
234→        assert!(tracker.can_afford(0.50));
235→        assert!(!tracker.can_afford(1.00)); // 0.06 + 1.00 > 1.0
236→    }
237→
238→    // --- BudgetTracker::record_cost ---
239→
240→    #[test]
241→    fn test_record_cost_updates_total() {
242→        let mut tracker = BudgetTracker::new(25.0);
243→        let pricing = ModelPricing::claude_sonnet();
244→
245→        let cost = tracker
246→            .record_cost("claude-sonnet", 10_000, 2_000, &pricing, "mutation call")
247→            .unwrap();
248→
249→        assert!((cost - 0.06).abs() < 0.0001);
250→        assert!((tracker.total_spent_usd - 0.06).abs() < 0.0001);
251→        assert_eq!(tracker.records.len(), 1);
252→        assert_eq!(tracker.records[0].model, "claude-sonnet");
253→        assert_eq!(tracker.records[0].description, "mutation call");
254→        assert_eq!(tracker.records[0].input_tokens, 10_000);
255→        assert_eq!(tracker.records[0].output_tokens, 2_000);
256→    }
257→
258→    #[test]
259→    fn test_record_cost_rejects_over_budget() {
260→        let mut tracker = BudgetTracker::new(0.05);
261→        let pricing = ModelPricing::claude_sonnet();
262→
263→        // This costs ~$0.06 which exceeds the $0.05 cap
264→        let result = tracker.record_cost("claude", 10_000, 2_000, &pricing, "over budget");
265→        assert!(result.is_err());
266→        assert!(
267→            result.unwrap_err().to_string().contains("Budget exceeded"),
268→            "error message must mention budget exceeded"
